gcode:
; Adaptive Bed Mesh Macro
; vendor: example  model: generic  version: 1.0.0
;
; Performs a bed mesh calibration limited to the area actually used by the
; current print, then loads the resulting mesh.  Requires the [bed_mesh]
; section to be configured in printer.cfg.

[gcode_macro ADAPTIVE_MESH]
description: Calibrate bed mesh for the current print area
gcode:
    {% set min_x = printer.toolhead.axis_minimum.x %}
    {% set min_y = printer.toolhead.axis_minimum.y %}
    {% set max_x = printer.toolhead.axis_maximum.x %}
    {% set max_y = printer.toolhead.axis_maximum.y %}

    ; Use object area if available, fall back to full bed
    {% if printer.exclude_object is defined and printer.exclude_object.objects | length > 0 %}
        {% set all_points = printer.exclude_object.objects | map(attribute='polygon') | sum(start=[]) %}
        {% set mesh_min_x = (all_points | map(attribute=0) | min) | float %}
        {% set mesh_min_y = (all_points | map(attribute=1) | min) | float %}
        {% set mesh_max_x = (all_points | map(attribute=0) | max) | float %}
        {% set mesh_max_y = (all_points | map(attribute=1) | max) | float %}
    {% else %}
        {% set mesh_min_x = min_x %}
        {% set mesh_min_y = min_y %}
        {% set mesh_max_x = max_x %}
        {% set mesh_max_y = max_y %}
    {% endif %}

    BED_MESH_CALIBRATE MESH_MIN={mesh_min_x},{mesh_min_y} MESH_MAX={mesh_max_x},{mesh_max_y}
    BED_MESH_PROFILE LOAD=default
